// src/pages/MyLeaves.js
import React from 'react';
import { useApp } from '../context/AppContext';

export default function MyLeaves({ setActivePage }) {
  const { leaveRequests, currentUser } = useApp();

  const isAdmin = currentUser.role === 'admin';

  const myLeaves = isAdmin
    ? leaveRequests
    : leaveRequests.filter(r => r.teacherId === currentUser.id);

  const sorted = [...myLeaves].sort((a, b) => b.id - a.id);

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div>
          <h1 style={styles.title}>
            {isAdmin ? '📋 All Leave History' : '📋 My Leaves'}
          </h1>
          <p style={styles.subtitle}>{sorted.length} total request(s)</p>
        </div>

        {!isAdmin && (
          <button
            style={styles.applyBtn}
            onClick={() => setActivePage('Apply Leave')}
          >
            + Apply for Leave
          </button>
        )}
      </div>

      {sorted.length === 0 ? (
        <div style={styles.empty}>
          <div style={styles.emptyIcon}>📭</div>
          <div style={styles.emptyText}>No leave requests yet</div>
        </div>
      ) : (
        <div style={styles.list}>
          {sorted.map(req => (
            <LeaveCard key={req.id} req={req} />
          ))}
        </div>
      )}
    </div>
  );
}

function LeaveCard({ req }) {
  const { currentUser, acceptSubstitute } = useApp();
  const [showSubs, setShowSubs] = React.useState(false);

  const isLeaveOwner = currentUser.id === req.teacherId;

  return (
    <div style={styles.card}>
      <div style={styles.cardTop}>
        <div>
          <div style={styles.dateRange}>
            📅 {req.fromDate} → {req.toDate}
          </div>
          <div style={styles.reason}>📝 {req.reason}</div>
        </div>

        {req.substituteRequests.length > 0 && (
          <button
            style={styles.expandBtn}
            onClick={() => setShowSubs(!showSubs)}
          >
            {showSubs ? '▲ Hide Details' : '▼ View Substitutes'}
          </button>
        )}
      </div>

      {showSubs && (
        <div style={styles.subsSection}>
          {req.substituteRequests.map((sub, i) => {
            const isFreeTeacher =
              sub.freeTeachers?.some(t => t.id === currentUser.id);

              console.log("")

            const alreadyAccepted =
              sub.assignedTeacherId === currentUser.id;

            return (
              <div key={i} style={styles.subCard}>
                <div>
                  <strong>{sub.day}</strong> | Period {sub.period} | {sub.time}
                </div>

                <div>Class: {sub.class}</div>

                {sub.assignedTeacherId ? (
                  <div style={{ color: 'green', fontWeight: 600 }}>
                    ✔ Assigned to{' '}
                    {sub.freeTeachers?.find(
                      t => t.id === sub.assignedTeacherId
                    )?.name}
                  </div>
                ) : isFreeTeacher && !isLeaveOwner ? (
                  <button
                    style={styles.acceptBtn}
                    onClick={() =>
                      acceptSubstitute(req.id, i, currentUser.id)
                    }
                  >
                    Accept Class
                  </button>
                ) : (
                  <div style={{ color: '#dc2626' }}>
                    ⚠ Waiting for substitute
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { padding: 30, maxWidth: 900, margin: '0 auto' },
  header: { display: 'flex', justifyContent: 'space-between', marginBottom: 20 },
  title: { fontSize: 24, fontWeight: 800 },
  subtitle: { color: '#64748b' },
  applyBtn: {
    background: '#2563eb',
    color: '#fff',
    border: 'none',
    padding: '10px 20px',
    borderRadius: 8,
    cursor: 'pointer',
  },
  empty: { textAlign: 'center', padding: 40 },
  emptyIcon: { fontSize: 40 },
  emptyText: { color: '#94a3b8' },
  list: { display: 'flex', flexDirection: 'column', gap: 15 },
  card: {
    background: '#fff',
    padding: 20,
    borderRadius: 12,
    boxShadow: '0 2px 10px rgba(0,0,0,0.05)',
  },
  cardTop: { display: 'flex', justifyContent: 'space-between' },
  dateRange: { fontWeight: 700, color: '#1d4ed8' },
  reason: { marginTop: 5, color: '#64748b' },
  expandBtn: {
    background: '#f1f5f9',
    border: '1px solid #cbd5e1',
    padding: '5px 12px',
    borderRadius: 8,
    cursor: 'pointer',
  },
  subsSection: { marginTop: 15 },
  subCard: {
    border: '1px solid #e2e8f0',
    padding: 12,
    borderRadius: 8,
    marginBottom: 8,
  },
  acceptBtn: {
    background: '#16a34a',
    color: '#fff',
    border: 'none',
    padding: '6px 12px',
    borderRadius: 6,
    cursor: 'pointer',
    marginTop: 6,
  },
};
